class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

public class Solution {
    private static final int MOD = 1000000007;

    public int maxProduct(TreeNode root) {
        long total = dfs(root), result = 0;
        return (int) (dfs2(root, total / 2, result, total) % MOD);
    }

    private int dfs(TreeNode root) {
        return root == null ? 0 : root.val + dfs(root.left) + dfs(root.right);
    }

    private long dfs2(TreeNode root, double half, long result, long total) {
        if (root == null) return 0;
        int curSum = root.val + dfs2(root.left, half, result, total) + dfs2(root.right, half, result, total);
        result = Math.max(result, (total - curSum) * curSum);
        return curSum;
    }
}
```

